class Solution:
    def countDigitOne(self, n: int) -> int:
        count = 0
        i = 0
        while True:
            divisor = 10 ** i
            higher = n // (divisor * 10)
            current = (n // divisor) % 10
            lower = n % divisor
            if current > 1:
                count += (higher + 1) * divisor
            elif current == 1:
                count += higher * divisor + (lower + 1)
            else:
                count += higher * divisor
            if divisor > n:
                break
            i += 1
        return count

